Production Nginx configuration for proxying API requests with rate limiting, caching, and CORS.

```nginx
# Rate limiting zones
limit_req_zone $binary_remote_addr zone=api_general:10m rate=10r/s;
limit_req_zone $binary_remote_addr zone=api_auth:10m rate=3r/s;

# Cache zone for GET requests
proxy_cache_path /var/cache/nginx/api levels=1:2 keys_zone=api_cache:10m
  max_size=1g inactive=10m use_temp_path=off;

upstream api_backend {
  server 127.0.0.1:3000;
  keepalive 32;
}

server {
  listen 443 ssl http2;
  server_name api.myapp.com;

  # SSL
  ssl_certificate /etc/ssl/certs/myapp.pem;
  ssl_certificate_key /etc/ssl/private/myapp.key;

  # Security headers
  add_header X-Frame-Options DENY;
  add_header X-Content-Type-Options nosniff;
  add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;

  # API routes
  location /api/ {
    limit_req zone=api_general burst=20 nodelay;
    client_max_body_size 10m;

    proxy_pass http://api_backend;
    proxy_http_version 1.1;
    proxy_set_header Host $host;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    proxy_set_header X-Forwarded-Proto $scheme;
    proxy_set_header Connection "";

    # Timeout settings
    proxy_connect_timeout 5s;
    proxy_send_timeout 30s;
    proxy_read_timeout 30s;

    # Cache GET responses
    proxy_cache api_cache;
    proxy_cache_methods GET;
    proxy_cache_valid 200 1m;
    proxy_cache_use_stale error timeout updating;
    add_header X-Cache-Status $upstream_cache_status;
  }

  # Stricter rate limiting for auth endpoints
  location /api/auth/ {
    limit_req zone=api_auth burst=5 nodelay;

    proxy_pass http://api_backend;
    proxy_http_version 1.1;
    proxy_set_header Host $host;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

    # No caching for auth
    proxy_no_cache 1;
    proxy_cache_bypass 1;
  }

  # JSON error pages for API
  error_page 502 503 504 = @api_error;
  location @api_error {
    default_type application/json;
    return 503 '{"error":{"code":"SERVICE_UNAVAILABLE","message":"API is temporarily unavailable"}}';
  }
}
```

Key settings: `keepalive 32` reuses connections to the backend. `proxy_cache_use_stale` serves cached content when the backend is down. `burst=20 nodelay` allows short traffic spikes without queueing. JSON error pages prevent HTML responses from reaching API clients.
